43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const calculateComponentPremium = (type: string, count: number): number =>
48	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
49	
50	const calculateItemPremium = (item: Item): number => {
51	  const base = BASE_PREMIUMS[item.type] ?? 0;
52	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
53	  const enchantmentSurcharge =
54	    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
55	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
56	      : 0;
57	  return base + cursedSurcharge + enchantmentSurcharge;
58	};
59	
60	const calculateBasePremium = (items: Item[]): number => {
61	  const componentCounts = new Map<string, number>();
62	  let mainItemsPremium = 0;
63	
64	  for (const item of items) {
65	    if (COMPONENT_TYPES.has(item.type)) {
66	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
67	    } else {
68	      mainItemsPremium += calculateItemPremium(item);
69	    }
70	  }
71	
72	  let total = mainItemsPremium;
73	  for (const [type, count] of componentCounts) {
74	    total += calculateComponentPremium(type, count);
75	  }
76	
77	  return total;
78	};
