80	export function processScenario(scenario: Scenario): ScenarioOutput {
81	  let quoteCount = 0;
82	  const results = scenario.steps.map((step) => {
83	    quoteCount++;
84	    const basePremium = calculateBasePremium(step.items);
85	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
86	    const followUpDiscount = quoteCount > 1 ? basePremium * 0.15 : 0;
87	    const policyPremium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount;
88	    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
89	    return { premium };
90	  });
91	  return { results };
92	}
