66	    if (COMPONENT_TYPES.has(item.type)) {
67	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
68	    } else {
69	      mainItemsPremium += calculateItemPremium(item);
70	    }
71	  }
72	
73	  let total = mainItemsPremium;
74	  for (const [type, count] of componentCounts) {
75	    total += calculateComponentPremium(type, count);
76	  }
77	
78	  return total;
79	};
