81	export function processScenario(scenario: Scenario): ScenarioOutput {
82	  const results = scenario.steps.map((step, index) => {
83	    const basePremium = calculateBasePremium(step.items);
84	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
85	    const followUpDiscount = index > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
86	    const policyPremium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount;
87	    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
88	    return { premium };
89	  });
90	  return { results };
91	}
